// v0.6：Code node 直接打 Gemini API + 組 Markdown + 組 binary（合併原本的 HTTP Gemini + Code 兩個節點）

const GEMINI_API_KEY = '__GEMINI_API_KEY__';
const aggregated = $json;
const today = new Date().toISOString().slice(0, 10);

const prompt = '以下是今日多份輸入文件，請整理成結構化日報（繁體中文 Markdown）。包含：重點摘要 3-5 點、待辦事項（含優先級）、關鍵決策、風險或卡點。日期：' + today + '。直接輸出 Markdown，不要 markdown 標記包裹。\n\n<輸入文件>\n' + JSON.stringify(aggregated).substring(0, 8000) + '\n</輸入文件>';

let markdown;
let aiError = null;

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
    headers: {
      'Content-Type': 'application/json',
      'x-goog-api-key': GEMINI_API_KEY
    },
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.5, maxOutputTokens: 2000, thinkingConfig: { thinkingBudget: 0 } }
    },
    json: true,
    timeout: 60000
  });
  const raw = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  markdown = raw.replace(/```markdown\s*/i, '').replace(/```\s*$/, '').trim();
} catch (err) {
  aiError = err.message || String(err);
  markdown = '# 日報 - ' + today + '\n\n（AI 呼叫失敗：' + aiError + '）\n\n## 原始輸入摘要\n\n' + JSON.stringify(aggregated).substring(0, 1000);
}

if (!markdown || markdown.length < 5) {
  markdown = '# 日報 - ' + today + '\n\n（AI 回應為空，可能是輸入太少或 API 限額）';
}

const outputPath = '/files/shared/daily-output/daily-' + today + '.md';

return [{
  json: { outputPath, markdown, aiError, today },
  binary: {
    data: {
      data: Buffer.from(markdown).toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'daily-' + today + '.md'
    }
  }
}];
